import React, { useEffect, useState } from 'react'
import { pondService, environmentLogService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/manager/manager-common.css'
import '../../styles/technician/technician-thresholds.css'

const emptyThresholds = {
	minPh: '',
	maxPh: '',
	minTemp: '',
	maxTemp: '',
	minSalinity: '',
	maxSalinity: '',
	minOxygen: '',
	maxOxygen: '',
	minTurbidity: '',
	maxTurbidity: '',
}

const TechnicianThresholds = () => {
	const [ponds, setPonds] = useState([])
	const [selectedPondId, setSelectedPondId] = useState(null)
	const [selectedPond, setSelectedPond] = useState(null)
	const [thresholds, setThresholds] = useState(emptyThresholds)
	const [loading, setLoading] = useState(true)
	const [saving, setSaving] = useState(false)
	const [error, setError] = useState('')
	const [success, setSuccess] = useState('')

	useEffect(() => {
		fetchPonds()
	}, [])

	const fetchPonds = async () => {
		try {
			setLoading(true)
			const res = await pondService.getAllPonds()
			const pondsList = res?.data?.data || []
			setPonds(pondsList)

			if (pondsList.length > 0 && !selectedPondId) {
				const firstPond = pondsList[0]
				setSelectedPondId(firstPond.pond_id)
				setSelectedPond(firstPond)
				await fetchThresholds(firstPond.pond_id)
			}
			setError('')
		} catch (err) {
			setError(err?.response?.data?.message || 'Không tải được danh sách ao')
		} finally {
			setLoading(false)
		}
	}

	const fetchThresholds = async (pondId) => {
		try {
			const res = await environmentLogService.getThresholdsByPond(pondId)
			const data = res?.data?.data
			if (data) {
				setThresholds({
					minPh: data.min_ph ?? '',
					maxPh: data.max_ph ?? '',
					minTemp: data.min_temp ?? '',
					maxTemp: data.max_temp ?? '',
					minSalinity: data.min_salinity ?? '',
					maxSalinity: data.max_salinity ?? '',
					minOxygen: data.min_oxygen ?? '',
					maxOxygen: data.max_oxygen ?? '',
					minTurbidity: data.min_turbidity ?? '',
					maxTurbidity: data.max_turbidity ?? '',
				})
			} else {
				setThresholds(emptyThresholds)
			}
			setError('')
		} catch (err) {
			setThresholds(emptyThresholds)
			setError('')
		}
	}

	const handlePondChange = async (pondId) => {
		setSelectedPondId(pondId)
		const pond = ponds.find((p) => String(p.pond_id) === String(pondId))
		setSelectedPond(pond)
		await fetchThresholds(pondId)
		setSuccess('')
	}

	const handleChange = (field, value) => {
		setThresholds((prev) => ({
			...prev,
			[field]: value === '' ? '' : Number(value),
		}))
	}

	const handleSubmit = async (event) => {
		event.preventDefault()
		if (!selectedPondId) {
			setError('Vui lòng chọn ao')
			return
		}

		try {
			setSaving(true)
			setError('')
			setSuccess('')

			if (thresholds.minPh && thresholds.maxPh && thresholds.minPh > thresholds.maxPh) {
				setError('pH: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minTemp && thresholds.maxTemp && thresholds.minTemp > thresholds.maxTemp) {
				setError('Nhiệt độ: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minSalinity && thresholds.maxSalinity && thresholds.minSalinity > thresholds.maxSalinity) {
				setError('Độ mặn: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minOxygen && thresholds.maxOxygen && thresholds.minOxygen > thresholds.maxOxygen) {
				setError('Oxy: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minTurbidity && thresholds.maxTurbidity && thresholds.minTurbidity > thresholds.maxTurbidity) {
				setError('Độ đục: Min phải nhỏ hơn Max')
				return
			}

			const payload = {
				minPh: thresholds.minPh || null,
				maxPh: thresholds.maxPh || null,
				minTemp: thresholds.minTemp || null,
				maxTemp: thresholds.maxTemp || null,
				minSalinity: thresholds.minSalinity || null,
				maxSalinity: thresholds.maxSalinity || null,
				minOxygen: thresholds.minOxygen || null,
				maxOxygen: thresholds.maxOxygen || null,
				minTurbidity: thresholds.minTurbidity || null,
				maxTurbidity: thresholds.maxTurbidity || null,
			}

			await environmentLogService.setThresholdsByPond(selectedPondId, payload)
			setSuccess('✅ Lưu ngưỡng cảnh báo thành công')
			setTimeout(() => setSuccess(''), 3000)
		} catch (err) {
			setError(err?.response?.data?.message || 'Không lưu được ngưỡng cảnh báo')
		} finally {
			setSaving(false)
		}
	}

	if (loading) {
		return (
			<div className="dashboard-container manager-page">
				<div className="card">
					<p>Đang tải...</p>
				</div>
			</div>
		)
	}

	return (
		<div className="dashboard-container manager-page">
			<div className="threshold-header">
				<div className="threshold-left">
					<h3>Thiết lập ngưỡng môi trường</h3>
					<div className="threshold-selector">
						<label htmlFor="pond-select">Chọn ao:</label>
						<select
							id="pond-select"
							value={selectedPondId || ''}
							onChange={(e) => handlePondChange(e.target.value)}
							className="form-control"
						>
							<option value="">-- Chọn ao --</option>
							{ponds.map((pond) => (
								<option key={pond.pond_id} value={pond.pond_id}>
									{pond.pond_code} - {pond.pond_name}
								</option>
							))}
						</select>
					</div>
				</div>
				<div className="threshold-actions">
					<button onClick={handleSubmit} className="btn btn-primary" disabled={saving || !selectedPondId}>
						💾 {saving ? 'Đang lưu' : 'Lưu cấu hình'}
					</button>
				</div>
			</div>

			{error && <div className="alert alert-danger">{error}</div>}
			{success && <div className="alert alert-success">{success}</div>}

			<div className="threshold-cards">
				{/* metric card: pH */}
				<div className="metric-card">
					<div className="metric-header">
						<div className="metric-title">pH</div>
						<div className="metric-current">Giá trị hiện tại: -</div>
					</div>
					<div className="metric-body">
						<div className="metric-bar" />
						<div className="metric-inputs">
							<input
								type="number"
								step="0.1"
								value={thresholds.minPh}
								onChange={(e) => handleChange('minPh', e.target.value)}
								className="form-control"
								placeholder="Min"
							/>
							<input
								type="number"
								step="0.1"
								value={thresholds.maxPh}
								onChange={(e) => handleChange('maxPh', e.target.value)}
								className="form-control"
								placeholder="Max"
							/>
						</div>
					</div>
				</div>

				{/* temperature */}
				<div className="metric-card">
					<div className="metric-header">
						<div className="metric-title">Nhiệt độ (°C)</div>
						<div className="metric-current">Giá trị hiện tại: -</div>
					</div>
					<div className="metric-body">
						<div className="metric-bar" />
						<div className="metric-inputs">
							<input type="number" step="0.1" value={thresholds.minTemp} onChange={(e) => handleChange('minTemp', e.target.value)} className="form-control" placeholder="Min" />
							<input type="number" step="0.1" value={thresholds.maxTemp} onChange={(e) => handleChange('maxTemp', e.target.value)} className="form-control" placeholder="Max" />
						</div>
					</div>
				</div>

				{/* salinity */}
				<div className="metric-card">
					<div className="metric-header">
						<div className="metric-title">Độ mặn (ppt)</div>
						<div className="metric-current">Giá trị hiện tại: -</div>
					</div>
					<div className="metric-body">
						<div className="metric-bar" />
						<div className="metric-inputs">
							<input type="number" step="0.1" value={thresholds.minSalinity} onChange={(e) => handleChange('minSalinity', e.target.value)} className="form-control" placeholder="Min" />
							<input type="number" step="0.1" value={thresholds.maxSalinity} onChange={(e) => handleChange('maxSalinity', e.target.value)} className="form-control" placeholder="Max" />
						</div>
					</div>
				</div>

				{/* oxygen */}
				<div className="metric-card">
					<div className="metric-header">
						<div className="metric-title">Oxy (mg/L)</div>
						<div className="metric-current">Giá trị hiện tại: -</div>
					</div>
					<div className="metric-body">
						<div className="metric-bar" />
						<div className="metric-inputs">
							<input type="number" step="0.1" value={thresholds.minOxygen} onChange={(e) => handleChange('minOxygen', e.target.value)} className="form-control" placeholder="Min" />
							<input type="number" step="0.1" value={thresholds.maxOxygen} onChange={(e) => handleChange('maxOxygen', e.target.value)} className="form-control" placeholder="Max" />
						</div>
					</div>
				</div>

				{/* turbidity */}
				<div className="metric-card">
					<div className="metric-header">
						<div className="metric-title">Độ đục (NTU)</div>
						<div className="metric-current">Giá trị hiện tại: -</div>
					</div>
					<div className="metric-body">
						<div className="metric-bar" />
						<div className="metric-inputs">
							<input type="number" step="0.1" value={thresholds.minTurbidity} onChange={(e) => handleChange('minTurbidity', e.target.value)} className="form-control" placeholder="Min" />
							<input type="number" step="0.1" value={thresholds.maxTurbidity} onChange={(e) => handleChange('maxTurbidity', e.target.value)} className="form-control" placeholder="Max" />
						</div>
					</div>
				</div>
			</div>

			{/* Alert preview and history stub */}
			<div className="threshold-footer">
				<div className="alert-preview">
					<h4>Alert Preview</h4>
					<ul>
						<li>pH vượt ngưỡng tối đa</li>
						<li>DO dưới mức an toàn</li>
						<li>Nhiệt độ bất thường</li>
					</ul>
				</div>
				<div className="history">
					<h4>Lịch sử thiết lập</h4>
					<p>Hiện chưa có lịch sử hiển thị ở môi trường dev này.</p>
				</div>
			</div>
		</div>
	)
}

export default TechnicianThresholds
